async (params, browser) => {
  // Open Figma home
  await browser.open('https://www.figma.com/files/recents')

  // Wait for search input
  await browser.waitForSelector('input[placeholder*="Search"], [data-testid="search-input"], [class*="search"] input', 15000)

  // Let page stabilize
  await browser.wait(2000)

  // Click search input
  await browser.click('input[placeholder*="Search"], [data-testid="search-input"], [class*="search"] input, [class*="search_bar"], [class*="global_search"]')

  // Let search focus
  await browser.wait(500)

  // Type search query
  const type_result = await browser.evaluate(`const searchInput = document.querySelector('input[placeholder*="Search"], [data-testid="search-input"], [class*="search"] input'); if (!searchInput) throw new Error('Search input not found'); searchInput.focus(); const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSetter.call(searchInput, params.query); searchInput.dispatchEvent(new Event('input', { bubbles: true })); searchInput.dispatchEvent(new Event('change', { bubbles: true })); await new Promise(r => setTimeout(r, 300)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); return { typed: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Extract search results
  const result = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-testid="file-card"], .file_card, [class*="search_result"], [class*="file-browser-page"] .tile, [class*="search"] [class*="result_item"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const item = items[i]; const nameEl = item.querySelector('.file-name, [data-testid="filename"], [class*="file_name"], [class*="result_name"]'); const linkEl = item.querySelector('a[href*="/design/"], a[href*="/file/"], a[href*="/board/"]'); const thumbEl = item.querySelector('img[src*="figma"], img[class*="thumbnail"]'); const projectEl = item.querySelector('[class*="project_name"], [class*="folder"], [class*="breadcrumb"]'); results.push({ name: nameEl ? nameEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', thumbnail: thumbEl ? thumbEl.src : '', project: projectEl ? projectEl.textContent.trim() : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return result
}
